query:
CREATE TABLE `contacts` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `waId` varchar(50) NOT NULL, `name` varchar(255), `email` varchar(320), `phone` varchar(20), `profilePicUrl` varchar(1000), `tags` json, `customFields` json, `isBlocked` boolean NOT NULL DEFAULT false, `optedOut` boolean NOT NULL DEFAULT false, `source` varchar(100) DEFAULT 'whatsapp', `notes` text, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `contacts_id` PRIMARY KEY(`id`));
CREATE TABLE `conversations` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `contactId` int NOT NULL, `waId` varchar(50) NOT NULL, `status` enum('open','resolved','pending','bot') NOT NULL DEFAULT 'open', `assignedTo` int, `lastMessageAt` timestamp DEFAULT (now()), `lastMessageText` text, `unreadCount` int NOT NULL DEFAULT 0, `isArchived` boolean NOT NULL DEFAULT false, `tags` json, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `conversations_id` PRIMARY KEY(`id`));
CREATE TABLE `messages` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `conversationId` int NOT NULL, `contactId` int NOT NULL, `waMessageId` varchar(255), `direction` enum('inbound','outbound') NOT NULL, `type` enum('text','image','audio','video','document','location','template','interactive','sticker') NOT NULL DEFAULT 'text', `content` text, `mediaUrl` varchar(1000), `mediaCaption` text, `status` enum('sent','delivered','read','failed','pending') NOT NULL DEFAULT 'pending', `isAutoReply` boolean NOT NULL DEFAULT false, `isBotMessage` boolean NOT NULL DEFAULT false, `metadata` json, `sentAt` timestamp NOT NULL DEFAULT (now()), `deliveredAt` timestamp, `readAt` timestamp, `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `messages_id` PRIMARY KEY(`id`));
CREATE TABLE `leads` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `contactId` int, `conversationId` int, `name` varchar(255), `email` varchar(320), `phone` varchar(20) NOT NULL, `source` varchar(100) DEFAULT 'whatsapp', `status` enum('new','contacted','qualified','proposal','won','lost') NOT NULL DEFAULT 'new', `score` int DEFAULT 0, `assignedTo` int, `notes` text, `customFields` json, `tags` json, `lastContactedAt` timestamp, `estimatedValue` bigint, `closedAt` timestamp, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `leads_id` PRIMARY KEY(`id`))

